parameters.query:
SELECT id, name, class_name, manufacturer, category, subtype
FROM datap4k_weapons_norm
ORDER BY category, subtype, name;

parameters.jsCode:
const row = $input.first().json;
const slug = row.slug || (row.class_name || row.name || 'unknown')
  .toLowerCase().replace(/_/g, '-').replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
function catLabel(cat, sub) {
  if (cat === 'fps') return sub === 'Gadget' ? 'FPS Gadget' : 'FPS Weapon';
  if (cat === 'ship') {
    if (sub === 'Gun') return 'Ship Gun';
    if (sub === 'Missile') return 'Ship Missile';
    if (sub === 'Torpedo') return 'Ship Torpedo';
    return 'Ship Weapon';
  }
  if (cat === 'attachments') return 'Weapon Attachment';
  return cat || 'Weapon';
}
const categoryLabel = catLabel(row.category, row.subtype);
const typeLabel = row.display_type || row.subtype || '';
function parsePrices(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { return []; } }
  return Array.isArray(raw) ? raw : [];
}
function fmtNum(v, dec) {
  if (v === null || v === undefined) return null;
  const n = Number(v);
  if (!Number.isFinite(n) || n <= 0) return null;
  return n.toLocaleString('en-US', { minimumFractionDigits: dec || 0, maximumFractionDigits: dec || 0 });
}
const uexPrices = parsePrices(row.uex_prices);
const dp4kPrices = parsePrices(row.datap4k_prices);
const lines = [];
lines.push('# ' + row.name);
lines.push('');
lines.push('- **Category:** ' + categoryLabel);
if (typeLabel && typeLabel !== categoryLabel) lines.push('- **Type:** ' + typeLabel);
if (row.manufacturer) lines.push('- **Manufacturer:** ' + row.manufacturer);
if (row.size) lines.push('- **Size:** S' + row.size);
if (row.mag_capacity) lines.push('- **Magazine:** ' + row.mag_capacity + ' rounds');
if (row.fire_rate_rpm) lines.push('- **Fire Rate:** ' + Math.round(Number(row.fire_rate_rpm)) + ' RPM');
if (row.ammo_speed_ms) lines.push('- **Ammo Speed:** ' + Math.round(Number(row.ammo_speed_ms)) + ' m/s');
lines.push('');
const dmgRows = [
  ['Energy', fmtNum(row.dmg_energy, 2)],
  ['Physical', fmtNum(row.dmg_physical, 2)],
  ['Thermal', fmtNum(row.dmg_thermal, 2)],
  ['Distortion', fmtNum(row.dmg_distortion, 2)],
  ['Biochemical', fmtNum(row.dmg_biochemical, 2)]
].filter(r => r[1] !== null);
if (dmgRows.length > 0 || (row.total_damage && Number(row.total_damage) > 0)) {
  lines.push('## Damage');
  lines.push('');
  lines.push('| Type | Per Shot |');
  lines.push('|---|---|');
  dmgRows.forEach(r => lines.push('| ' + r[0] + ' | ' + r[1] + ' |'));
  if (row.total_damage && Number(row.total_damage) > 0) {
    lines.push('| **Total** | **' + fmtNum(row.total_damage, 2) + '** |');
  }
  lines.push('');
}
if (row.ideal_range_m || row.max_range_m) {
  lines.push('## Range');
  lines.push('');
  lines.push('| Ideal Range | Max Range |');
  lines.push('|---|---|');
  lines.push('| ' + (fmtNum(row.ideal_range_m, 0) || '-') + ' m | ' + (fmtNum(row.max_range_m, 0) || '-') + ' m |');
  lines.push('');
}
lines.push('## Availability');
lines.push('');
if (uexPrices.length > 0) {
  lines.push('> _Prices from UEX (live data)._');
  lines.push('');
  lines.push('| Terminal | Buy (aUEC) | Sell (aUEC) |');
  lines.push('|---|---|---|');
  uexPrices.forEach(p => lines.push('| ' + p.terminal + ' | ' + (fmtNum(p.buy, 0) || '-') + ' | ' + (fmtNum(p.sell, 0) || '-') + ' |'));
} else if (dp4kPrices.length > 0) {
  lines.push('> _Prices from DataPack (may be outdated)._');
  lines.push('');
  lines.push('| Shop | Location | Buy (aUEC) | Sell (aUEC) |');
  lines.push('|---|---|---|---|');
  dp4kPrices.forEach(dp => lines.push('| ' + dp.shop + ' | ' + dp.location + ' | ' + (fmtNum(dp.buy, 0) || '-') + ' | ' + (fmtNum(dp.sell, 0) || '-') + ' |'));
} else {
  lines.push('_No purchase pricing currently available._');
}
return [{ json: { item_id: row.id, slug, name: row.name, markdown_detailed: lines.join('\n') } }];

const item = $input.first().json;
const slug = (item.slug || '').replace(/'/g, "''");
const content = (item.markdown_detailed || '').replace(/'/g, "''");
const query = "INSERT INTO kb_content (entity_slug, entity_type, entity_id, content, source_workflow, generated_at, updated_at) "
  + "VALUES ('" + slug + "', 'weapon', NULL, '" + content + "', 'KB - Weapons Markdown v1', now(), now()) "
  + "ON CONFLICT (entity_slug, entity_type) DO UPDATE SET content = EXCLUDED.content, "
  + "source_workflow = EXCLUDED.source_workflow, generated_at = EXCLUDED.generated_at, updated_at = now()";
return [{ json: { query, entity_slug: item.slug } }];
